body.script:
// The SVG itself is at a real https URL on jsdelivr, so location.href
// works and service workers can register. We fetch index1.html as
// text (bypassing jsdelivr's HTML mime weirdness), extract its
// <script> body, and run it here in the SVG document.

const HTML_URL = "https://cdn.jsdelivr.net/gh/sealiee11/gnmathpr0-y2@main/index1.html";

const fail = msg => {
  const status = document.getElementById("status");
  const detail = document.getElementById("detail");
  const error  = document.getElementById("error");
  if (status) status.textContent = "Error";
  if (detail) detail.style.display = "none";
  if (error)  { error.style.display = "block"; error.textContent = msg; }
};

fetch(HTML_URL + "?t=" + Date.now())
  .then(r => {
    if (!r.ok) throw new Error("Fetch " + HTML_URL + " -> HTTP " + r.status);
    return r.text();
  })
  .then(html => {
    const m = html.match(/<script>([\s\S]*?)<\/script\s*>/i);
    if (!m) throw new Error("No <script> block found in index1.html");
    const s = document.createElement("script");
    s.textContent = m[1];
    document.body.appendChild(s);
  })
  .catch(err => {
    console.error(err);
    fail("Bootstrap failed: " + err.message);
  });
